#include<bits/stdc++.h>
using namespace std;
#define ll long long
#define dbg(x) cerr<<#x" = "<<(x)<<'\n';
const int N=5005;
int n,m,ans[N],ans2[N];
struct node
{
	int u,w;
	bool operator<(const node other)  const
	{
		return w>other.w;
	}
};
priority_queue<node> pq;
vector<node> g[N];
void dij()
{
	memset(ans,0x3f,sizeof(ans));
	memset(ans2,0x3f,sizeof(ans2));
	ans[1]=0;
	pq.push(node{1,0});
	while(!pq.empty())
	{
		node t=pq.top();
		pq.pop();
		int u=t.u;
		ll w=t.w;
//		cout<<u<<" "<<w<<"\n";
		if(w>ans2[u]) continue;
		for(int i=0;i<g[u].size();i++)
		{
			node tt=g[u][i];
			int v=tt.u,ww=tt.w;
			if(w+ww<ans[v])
			{
				ans2[v]=ans[v];
				ans[v]=w+ww;
				pq.push(node{v,ans[v]});
			}
			else if(w+ww!=ans[v]&&w+ww<ans2[v])
			{
				ans2[v]=w+ww;
				pq.push(node{v,ans2[v]});
			}
		}
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		int u,v,w;
		cin>>u>>v>>w;
		g[u].push_back(node{v,w});
		g[v].push_back(node{u,w});
	}
	dij();
	cout<<ans2[n];
	return 0;
}
